// MVVM with SwiftUI
@Observable final class ProfileVM {
  var user: User?
  var error: String?
  func reload() async {
    do { user = try await api.fetch() } catch { self.error = "\(error)" }
  }
}
struct ProfileView: View {
  @State var vm = ProfileVM()
  var body: some View { Text(vm.user?.name ?? "").task { await vm.reload() } }
}

