class AppCoordinator {
  let nav: UINavigationController
  init(nav: UINavigationController) { self.nav = nav }
  func start() { nav.setViewControllers([HomeVC(coordinator: self)], animated: false) }
  func showProfile() { nav.pushViewController(ProfileVC(), animated: true) }
  func showLogin() { nav.present(LoginVC(), animated: true) }
}

