// Before — fat VC
class ProfileVC: UIViewController, UITableViewDataSource {
  // owns model, network, table data source, navigation — too much
}

// After — split responsibilities
final class ProfileVM {
  private let api: ProfileAPI
  init(api: ProfileAPI) { self.api = api }
  func load() async throws -> Profile { try await api.fetch() }
}

final class ActivityDataSource: NSObject, UITableViewDataSource {
  var items: [Activity] = []
  func tableView(_ tv: UITableView, numberOfRowsInSection s: Int) -> Int { items.count }
  func tableView(_ tv: UITableView, cellForRowAt ip: IndexPath) -> UITableViewCell {
    let cell = tv.dequeueReusableCell(withIdentifier: "c", for: ip)
    cell.textLabel?.text = items[ip.row].title
    return cell
  }
}

final class ProfileVC: UIViewController {
  private let vm: ProfileVM
  private let coordinator: AppCoordinator
  private let dataSource = ActivityDataSource()
  private let tableView = UITableView()

  init(vm: ProfileVM, coordinator: AppCoordinator) {
    self.vm = vm; self.coordinator = coordinator
    super.init(nibName: nil, bundle: nil)
  }
  required init?(coder: NSCoder) { fatalError() }

  override func viewDidLoad() {
    super.viewDidLoad()
    tableView.dataSource = dataSource
    Task {
      let profile = try await vm.load()
      dataSource.items = profile.activities
      tableView.reloadData()
    }
  }

  @objc func tapShare() { coordinator.showShareSheet() }
}

protocol Coordinator: AnyObject {
  var children: [Coordinator] { get set }
  func start()
}

final class AppCoordinator: Coordinator {
  var children: [Coordinator] = []
  let nav: UINavigationController
  init(nav: UINavigationController) { self.nav = nav }

  func start() {
    if Session.current.isAuthenticated {
      pushHome()
    } else {
      pushLogin()
    }
  }

  func pushLogin() {
    let login = LoginCoordinator(nav: nav, parent: self)
    children.append(login)
    login.start()
  }

  func pushHome() {
    let home = HomeCoordinator(nav: nav, parent: self)
    children.append(home)
    home.start()
  }
}

final class LoginCoordinator: Coordinator {
  var children: [Coordinator] = []
  let nav: UINavigationController
  weak var parent: AppCoordinator?
  init(nav: UINavigationController, parent: AppCoordinator) {
    self.nav = nav; self.parent = parent
  }
  func start() {
    let vc = LoginVC()
    vc.onLoginSuccess = { [weak self] in
      guard let parent = self?.parent else { return }
      parent.children.removeAll { $0 === self }
      parent.pushHome()
    }
    nav.setViewControllers([vc], animated: true)
  }
}

