// Define abstractions
protocol UserAPI { func fetch(id: String) async throws -> User }
protocol AnalyticsClient { func track(_ event: String) }

// Production impls
struct ProdUserAPI: UserAPI { func fetch(id: String) async throws -> User { /* HTTP */ User(id: id) } }
struct ProdAnalytics: AnalyticsClient { func track(_ e: String) {} }

// Constructor injection — explicit
final class ProfileVM {
  private let api: UserAPI
  private let analytics: AnalyticsClient
  init(api: UserAPI, analytics: AnalyticsClient) {
    self.api = api; self.analytics = analytics
  }
  func load(_ id: String) async throws -> User {
    analytics.track("profile_load")
    return try await api.fetch(id: id)
  }
}

// Composition root — App entry wires the graph
@main
struct MyApp: App {
  let api: UserAPI = ProdUserAPI()
  let analytics: AnalyticsClient = ProdAnalytics()
  var body: some Scene {
    WindowGroup {
      ProfileScreen(vm: ProfileVM(api: api, analytics: analytics))
    }
  }
}

// Tests use fakes — no container needed
struct FakeUserAPI: UserAPI {
  func fetch(id: String) async throws -> User { User(id: id, name: "Test") }
}
let vm = ProfileVM(api: FakeUserAPI(), analytics: NoopAnalytics())

